SELECT CAST(
  (SELECT COUNT(*) FROM (
     SELECT e.event_id
     FROM event e
     LEFT JOIN budget b ON e.event_id = b.link_to_event
     GROUP BY e.event_id
     HAVING SUM(CASE WHEN b.remaining < 0 THEN 1 ELSE 0 END) > 0
   )
  ) AS REAL
) * 100.0 / (SELECT COUNT(*) FROM event) AS percentage_over_budget;	----- bird -----	student_club
